const response = $('Planifier Stories Hebdo').first().json;
const storyData = $('Charger Creneaux Stories').first().json;
const slots = storyData.slots || [];
const content = response.choices && response.choices[0] && response.choices[0].message ? response.choices[0].message.content : '';
let plan;
try {
  plan = JSON.parse(content);
} catch (e) {
  const match = content.match(/\{[\s\S]*\}/);
  if (match) {
    try { plan = JSON.parse(match[0]); } catch (e2) {}
  }
}
if (!plan || !plan.briefs || !Array.isArray(plan.briefs)) {
  return [{ json: { ...storyData, _planningFailed: true } }];
}
const enrichedSlots = slots.map((slot, i) => {
  const brief = plan.briefs.find(b => b.index === i);
  if (!brief) return slot;
  return {
    ...slot,
    _brief: {
      accroche_type: brief.accroche_type || '',
      angle_enrichi: brief.angle_enrichi || '',
      ton_cible: brief.ton_cible || '',
      differentiation: brief.differentiation || '',
      mots_interdits: brief.mots_interdits || []
    }
  };
});
return [{ json: { ...storyData, slots: enrichedSlots } }];
